// Helper to generate random tokens
function generateToken(length = 32) {
  return crypto.randomBytes(length).toString('hex');
}

// Helper to validate client
function validateClient(clientId, redirectUri) {
  const client = clients.get(clientId);
  if (!client) return null;
  if (redirectUri && !client.redirect_uris.includes(redirectUri)) return null;
  return client;
}

// Helper to build redirect URL with params
function buildRedirectUrl(baseUrl, params) {
  const parsedUrl = new URL(baseUrl);
  Object.entries(params).forEach(([key, value]) => {
    if (value !== undefined && value !== null) {
      parsedUrl.searchParams.set(key, value);
    }
  });
  return parsedUrl.toString();
}

