// POST /token - Token endpoint
app.post('/token', (req, res) => {
  const {
    grant_type,
    code,
    redirect_uri,
    client_id,
    client_secret,
    refresh_token
  } = req.body;

  // Also support Basic auth for client credentials
  let authenticatedClientId = client_id;
  let authenticatedClientSecret = client_secret;

  const authHeader = req.headers['authorization'];
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf8');
    const [headerClientId, headerClientSecret] = decoded.split(':');
    authenticatedClientId = authenticatedClientId || headerClientId;
    authenticatedClientSecret = authenticatedClientSecret || headerClientSecret;
  }

  // Validate grant_type
  if (grant_type === 'authorization_code') {
    // Validate required parameters
    if (!code) {
      return res.status(400).json({
        error: 'invalid_request',
        error_description: 'Authorization code is required'
      });
    }

    if (!authenticatedClientId) {
      return res.status(400).json({
        error: 'invalid_request',
        error_description: 'client_id is required'
      });
    }

    // Authenticate client
    const client = clients.get(authenticatedClientId);
    if (!client) {
      return res.status(401).json({
        error: 'invalid_client',
        error_description: 'Client authentication failed'
      });
    }

    if (authenticatedClientSecret && client.client_secret !== authenticatedClientSecret) {
      return res.status(401).json({
        error: 'invalid_client',
        error_description: 'Client authentication failed'
      });
    }

    // Validate authorization code
    const codeData = authorizationCodes.get(code);
    if (!codeData) {
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Invalid authorization code'
      });
    }

    // Check if code has been used (prevent replay attacks)
    if (codeData.used) {
      // If code was already used, revoke any tokens issued with it
      console.log(`[SECURITY] Authorization code reuse detected for client "${authenticatedClientId}"`);
      authorizationCodes.delete(code);
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Authorization code has already been used'
      });
    }

    // Check if code has expired (10 minutes)
    if (Date.now() - codeData.createdAt > 10 * 60 * 1000) {
      authorizationCodes.delete(code);
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Authorization code has expired'
      });
    }

    // Validate client matches
    if (codeData.clientId !== authenticatedClientId) {
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Authorization code was not issued to this client'
      });
    }

    // Validate redirect_uri matches
    if (redirect_uri && redirect_uri !== codeData.redirectUri) {
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'redirect_uri does not match the one used in authorization request'
      });
    }

    // Mark code as used
    codeData.used = true;

    // Generate access token and refresh token
    const accessToken = generateToken(32);
    const refreshTokenValue = generateToken(32);
    const expiresIn = 3600; // 1 hour

    // Store access token
    accessTokens.set(accessToken, {
      clientId: authenticatedClientId,
      username: codeData.username,
      scope: codeData.scope,
      createdAt: Date.now(),
      expiresIn: expiresIn,
      tokenType: 'access_token'
    });

    // Store refresh token
    accessTokens.set(refreshTokenValue, {
      clientId: authenticatedClientId,
      username: codeData.username,
      scope: codeData.scope,
      createdAt: Date.now(),
      expiresIn: 30 * 24 * 3600, // 30 days
      tokenType: 'refresh_token'
    });

    console.log(`[TOKEN] Access token issued for user "${codeData.username}" client "${authenticatedClientId}"`);

    // Return token response
    res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: expiresIn,
      refresh_token: refreshTokenValue,
      scope: codeData.scope
    });

  } else if (grant_type === 'refresh_token') {
    // Handle refresh token grant
    if (!refresh_token) {
      return res.status(400).json({
        error: 'invalid_request',
        error_description: 'refresh_token is required'
      });
    }

    // Authenticate client
    const client = clients.get(authenticatedClientId);
    if (!client || (authenticatedClientSecret && client.client_secret !== authenticatedClientSecret)) {
      return res.status(401).json({
        error: 'invalid_client',
        error_description: 'Client authentication failed'
      });
    }

    // Validate refresh token
    const tokenData = accessTokens.get(refresh_token);
    if (!tokenData || tokenData.tokenType !== 'refresh_token') {
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Invalid refresh token'
      });
    }

    // Check if refresh token has expired
    if (Date.now() - tokenData.createdAt > tokenData.expiresIn * 1000) {
      accessTokens.delete(refresh_token);
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Refresh token has expired'
      });
    }

    // Validate client matches
    if (tokenData.clientId !== authenticatedClientId) {
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Refresh token was not issued to this client'
      });
    }

    // Generate new access token
    const newAccessToken = generateToken(32);
    const newRefreshToken = generateToken(32);
    const expiresIn = 3600;

    // Store new access token
    accessTokens.set(newAccessToken, {
      clientId: authenticatedClientId,
      username: tokenData.username,
      scope: tokenData.scope,
      createdAt: Date.now(),
      expiresIn: expiresIn,
      tokenType: 'access_token'
    });

    // Store new refresh token and revoke old one
    accessTokens.delete(refresh_token);
    accessTokens.set(newRefreshToken, {
      clientId: authenticatedClientId,
      username: tokenData.username,
      scope: tokenData.scope,
      createdAt: Date.now(),
      expiresIn: 30 * 24 * 3600,
      tokenType: 'refresh_token'
    });

    console.log(`[TOKEN] Access token refreshed for user "${tokenData.username}" client "${authenticatedClientId}"`);

    res.json({
      access_token: newAccessToken,
      token_type: 'Bearer',
      expires_in: expiresIn,
      refresh_token: newRefreshToken,
      scope: tokenData.scope
    });

  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Only authorization_code and refresh_token grant types are supported'
    });
  }
});

// Token introspection endpoint (for resource servers)
app.post('/introspect', (req, res) => {
  const { token } = req.body;

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'token is required'
    });
  }

  const tokenData = accessTokens.get(token);

  if (!tokenData || tokenData.tokenType !== 'access_token') {
    return res.json({ active: false });
  }

  // Check expiration
  if (Date.now() - tokenData.createdAt > tokenData.expiresIn * 1000) {
    accessTokens.delete(token);
    return res.json({ active: false });
  }

  res.json({
    active: true,
    scope: tokenData.scope,
    client_id: tokenData.clientId,
    username: tokenData.username,
    token_type: 'Bearer',
    exp: Math.floor((tokenData.createdAt + tokenData.expiresIn * 1000) / 1000),
    iat: Math.floor(tokenData.createdAt / 1000)
  });
});

// Protected resource endpoint (example)
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers['authorization'];

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token is required'
    });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData || tokenData.tokenType !== 'access_token') {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Invalid access token'
    });
  }

  // Check expiration
  if (Date.now() - tokenData.createdAt > tokenData.expiresIn * 1000) {
    accessTokens.delete(token);
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token has expired'
    });
  }

  const user = users.get(tokenData.username);

  res.json({
    sub: user.username,
    name: user.name,
    scope: tokenData.scope
  });
});

// Token revocation endpoint
app.post('/revoke', (req, res) => {
  const { token, token_type_hint } = req.body;

  if (token) {
    accessTokens.delete(token);
  }

  // Always return 200 per RFC 7009
  res.status(200).json({ message: 'Token revoked' });
});

// Server metadata endpoint (RFC 8414)
app.get('/.well-known/oauth-authorization-server', (req, res) => {
  const baseUrl = `${req.protocol}://${req.get('host')}`;
  res.json({
    issuer: baseUrl,
    authorization_endpoint: `${baseUrl}/authorize`,
    token_endpoint: `${baseUrl}/token`,
    token_endpoint_auth_methods_supported: ['client_secret_post', 'client_secret_basic'],
    introspection_endpoint: `${baseUrl}/introspect`,
    revocation_endpoint: `${baseUrl}/revoke`,
    userinfo_endpoint: `${baseUrl}/userinfo`,
    response_types_supported: ['code'],
    grant_types_supported: ['authorization_code', 'refresh_token'],
    scopes_supported: ['read', 'write', 'admin'],
    code_challenge_methods_supported: ['S256']
  });
});

