// Admin endpoint to register new clients (for internal use)
app.post('/admin/clients', (req, res) => {
  const { client_id, client_secret, redirect_uris, name } = req.body;

  if (!client_id || !client_secret || !redirect_uris || !name) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'client_id, client_secret, redirect_uris, and name are required'
    });
  }

  if (clients.has(client_id)) {
    return res.status(409).json({
      error: 'conflict',
      error_description: 'Client with this client_id already exists'
    });
  }

  clients.set(client_id, {
    client_id,
    client_secret,
    redirect_uris: Array.isArray(redirect_uris) ? redirect_uris : [redirect_uris],
    name
  });

  console.log(`[ADMIN] New client registered: "${name}" (${client_id})`);

  res.status(201).json({
    client_id,
    name,
    redirect_uris: clients.get(client_id).redirect_uris
  });
});

